lemma SumSeqAppend(s: seq<int>, x: int)
  ensures SumSeq(s + [x]) == SumSeq(s) + x
{
  assert (s + [x])[..|s|] == s;
}

lemma CoalitionSeatSumAppend(a: seq<int>, c: seq<int>, v: int)
  requires 1 <= v <= |a|
  ensures CoalitionSeatSum(a, c + [v]) == CoalitionSeatSum(a, c) + a[v - 1]
{
